import{_ as a,c as t,o as i,a1 as l}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Журнал изменений: История версий | everything-claude-code","description":"Узнайте историю версий everything-claude-code и важные изменения. Отслеживайте новые функции, исправления безопасности и обновления документации.","frontmatter":{"title":"Журнал изменений: История версий | everything-claude-code","sidebarTitle":"Что нового","subtitle":"Журнал изменений: История версий","description":"Узнайте историю версий everything-claude-code и важные изменения. Отслеживайте новые функции, исправления безопасности и обновления документации.","tags":["changelog","updates"],"prerequisite":[],"order":250},"headers":[],"relativePath":"ru/affaan-m/everything-claude-code/changelog/release-notes/index.md","filePath":"ru/affaan-m/everything-claude-code/changelog/release-notes/index.md"}'),o={name:"ru/affaan-m/everything-claude-code/changelog/release-notes/index.md"};function r(d,e,n,s,h,c){return i(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="журнал-изменении-история-версии-и-изменения" tabindex="-1">Журнал изменений: История версий и изменения <a class="header-anchor" href="#журнал-изменении-история-версии-и-изменения" aria-label="Permalink to &quot;Журнал изменений: История версий и изменения&quot;">​</a></h1><h2 id="чему-вы-научитесь" tabindex="-1">Чему вы научитесь <a class="header-anchor" href="#чему-вы-научитесь" aria-label="Permalink to &quot;Чему вы научитесь&quot;">​</a></h2><ul><li>Узнавать о важных изменениях в каждой версии</li><li>Отслеживать новые функции и исправления</li><li>Решать, нужно ли обновляться</li></ul><h2 id="история-версии" tabindex="-1">История версий <a class="header-anchor" href="#история-версии" aria-label="Permalink to &quot;История версий&quot;">​</a></h2><h3 id="_2026-01-24-—-исправления-безопасности-и-документации" tabindex="-1">2026-01-24 — Исправления безопасности и документации <a class="header-anchor" href="#_2026-01-24-—-исправления-безопасности-и-документации" aria-label="Permalink to &quot;2026-01-24 — Исправления безопасности и документации&quot;">​</a></h3><p><strong>Исправления</strong>:</p><ul><li>🔒 <strong>Безопасность</strong>: Устранена уязвимость инъекции команд в <code>commandExists()</code><ul><li>Использование <code>spawnSync</code> вместо <code>execSync</code></li><li>Валидация ввода: разрешены только буквы, цифры, дефисы, подчёркивания и точки</li></ul></li><li>📝 <strong>Документация</strong>: Добавлено предупреждение о безопасности для <code>runCommand()</code></li><li>🐛 <strong>XSS-сканер</strong>: Исправлены ложные срабатывания — <code>&lt;script&gt;</code> и <code>&lt;binary&gt;</code> заменены на <code>[script-name]</code> и <code>[binary-name]</code></li><li>📚 <strong>Документация</strong>: Исправлена команда <code>npx ts-morph</code> на корректную <code>npx tsx scripts/codemaps/generate.ts</code> в <code>doc-updater.md</code></li></ul><p><strong>Затронутые issues</strong>: #42, #43, #51</p><hr><h3 id="_2026-01-22-—-кроссплатформенность-и-плагинизация" tabindex="-1">2026-01-22 — Кроссплатформенность и плагинизация <a class="header-anchor" href="#_2026-01-22-—-кроссплатформенность-и-плагинизация" aria-label="Permalink to &quot;2026-01-22 — Кроссплатформенность и плагинизация&quot;">​</a></h3><p><strong>Новые возможности</strong>:</p><ul><li>🌐 <strong>Кроссплатформенная поддержка</strong>: Все хуки и скрипты переписаны на Node.js, поддержка Windows, macOS и Linux</li><li>📦 <strong>Плагин-пакет</strong>: Распространение как плагин Claude Code с поддержкой установки через маркетплейс</li><li>🎯 <strong>Автоопределение пакетного менеджера</strong>: 6 уровней приоритета <ul><li>Переменная окружения <code>CLAUDE_PACKAGE_MANAGER</code></li><li>Конфигурация проекта <code>.claude/package-manager.json</code></li><li>Поле <code>packageManager</code> в <code>package.json</code></li><li>Определение по lock-файлам (package-lock.json, yarn.lock, pnpm-lock.yaml, bun.lockb)</li><li>Глобальная конфигурация <code>~/.claude/package-manager.json</code></li><li>Fallback на первый доступный пакетный менеджер</li></ul></li></ul><p><strong>Исправления</strong>:</p><ul><li>🔄 <strong>Загрузка хуков</strong>: Автоматическая загрузка по соглашению, удалено объявление хуков в <code>plugin.json</code></li><li>📌 <strong>Пути хуков</strong>: Использование <code>${CLAUDE_PLUGIN_ROOT}</code> и относительных путей</li><li>🎨 <strong>Улучшения UI</strong>: Добавлены график истории звёзд и панель бейджей</li><li>📖 <strong>Организация хуков</strong>: Хуки session-end перенесены из Stop в SessionEnd</li></ul><hr><h3 id="_2026-01-20-—-улучшения-функциональности" tabindex="-1">2026-01-20 — Улучшения функциональности <a class="header-anchor" href="#_2026-01-20-—-улучшения-функциональности" aria-label="Permalink to &quot;2026-01-20 — Улучшения функциональности&quot;">​</a></h3><p><strong>Новые возможности</strong>:</p><ul><li>💾 <strong>Memory Persistence Hooks</strong>: Автоматическое сохранение и загрузка контекста между сессиями</li><li>🧠 <strong>Strategic Compact Hook</strong>: Интеллектуальные рекомендации по сжатию контекста</li><li>📚 <strong>Continuous Learning Skill</strong>: Автоматическое извлечение переиспользуемых паттернов из сессий</li><li>🎯 <strong>Strategic Compact Skill</strong>: Стратегии оптимизации токенов</li></ul><hr><h3 id="_2026-01-17-—-первыи-релиз" tabindex="-1">2026-01-17 — Первый релиз <a class="header-anchor" href="#_2026-01-17-—-первыи-релиз" aria-label="Permalink to &quot;2026-01-17 — Первый релиз&quot;">​</a></h3><p><strong>Начальный функционал</strong>:</p><ul><li>✨ Полная коллекция конфигураций Claude Code</li><li>🤖 9 специализированных агентов</li><li>⚡ 14 слэш-команд</li><li>📋 8 наборов правил</li><li>🔄 Автоматизированные хуки</li><li>🎨 11 навыков (skills)</li><li>🌐 15+ предконфигурированных MCP-серверов</li><li>📖 Полная документация README</li></ul><hr><h2 id="схема-именования-версии" tabindex="-1">Схема именования версий <a class="header-anchor" href="#схема-именования-версии" aria-label="Permalink to &quot;Схема именования версий&quot;">​</a></h2><p>Проект не использует традиционное семантическое версионирование, а применяет <strong>формат даты</strong> (<code>YYYY-MM-DD</code>).</p><h3 id="типы-изменении" tabindex="-1">Типы изменений <a class="header-anchor" href="#типы-изменении" aria-label="Permalink to &quot;Типы изменений&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Тип</th><th>Описание</th><th>Пример</th></tr></thead><tbody><tr><td><strong>Новая функция</strong></td><td>Добавление функции или значительное улучшение</td><td><code>feat: add new agent</code></td></tr><tr><td><strong>Исправление</strong></td><td>Исправление бага или проблемы</td><td><code>fix: resolve hook loading issue</code></td></tr><tr><td><strong>Документация</strong></td><td>Обновление документации</td><td><code>docs: update README</code></td></tr><tr><td><strong>Стиль</strong></td><td>Форматирование или стиль кода</td><td><code>style: fix indentation</code></td></tr><tr><td><strong>Рефакторинг</strong></td><td>Рефакторинг кода</td><td><code>refactor: simplify hook logic</code></td></tr><tr><td><strong>Производительность</strong></td><td>Оптимизация производительности</td><td><code>perf: improve context loading</code></td></tr><tr><td><strong>Тесты</strong></td><td>Связанное с тестами</td><td><code>test: add unit tests</code></td></tr><tr><td><strong>Сборка</strong></td><td>Система сборки или зависимости</td><td><code>build: update package.json</code></td></tr><tr><td><strong>Откат</strong></td><td>Откат предыдущего коммита</td><td><code>revert: remove version field</code></td></tr></tbody></table><hr><h2 id="как-получить-обновления" tabindex="-1">Как получить обновления <a class="header-anchor" href="#как-получить-обновления" aria-label="Permalink to &quot;Как получить обновления&quot;">​</a></h2><h3 id="обновление-через-маркетплеис" tabindex="-1">Обновление через маркетплейс <a class="header-anchor" href="#обновление-через-маркетплеис" aria-label="Permalink to &quot;Обновление через маркетплейс&quot;">​</a></h3><p>Если вы установили Everything Claude Code через маркетплейс плагинов:</p><ol><li>Откройте Claude Code</li><li>Выполните <code>/plugin update everything-claude-code</code></li><li>Дождитесь завершения обновления</li></ol><h3 id="ручное-обновление" tabindex="-1">Ручное обновление <a class="header-anchor" href="#ручное-обновление" aria-label="Permalink to &quot;Ручное обновление&quot;">​</a></h3><p>Если вы клонировали репозиторий вручную:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.claude/plugins/everything-claude-code</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pull</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main</span></span></code></pre></div><h3 id="установка-из-маркетплеиса" tabindex="-1">Установка из маркетплейса <a class="header-anchor" href="#установка-из-маркетплеиса" aria-label="Permalink to &quot;Установка из маркетплейса&quot;">​</a></h3><p>Первая установка:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> marketplace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> affaan-m/everything-claude-code</span></span></code></pre></div><hr><h2 id="анализ-влияния-изменении" tabindex="-1">Анализ влияния изменений <a class="header-anchor" href="#анализ-влияния-изменении" aria-label="Permalink to &quot;Анализ влияния изменений&quot;">​</a></h2><h3 id="исправления-безопасности-обязательное-обновление" tabindex="-1">Исправления безопасности (обязательное обновление) <a class="header-anchor" href="#исправления-безопасности-обязательное-обновление" aria-label="Permalink to &quot;Исправления безопасности (обязательное обновление)&quot;">​</a></h3><ul><li><strong>2026-01-24</strong>: Исправлена уязвимость инъекции команд — настоятельно рекомендуется обновиться</li></ul><h3 id="улучшения-функциональности-опциональное-обновление" tabindex="-1">Улучшения функциональности (опциональное обновление) <a class="header-anchor" href="#улучшения-функциональности-опциональное-обновление" aria-label="Permalink to &quot;Улучшения функциональности (опциональное обновление)&quot;">​</a></h3><ul><li><strong>2026-01-22</strong>: Кроссплатформенная поддержка — обязательно для пользователей Windows</li><li><strong>2026-01-20</strong>: Новые функции — обновляйтесь по необходимости</li></ul><h3 id="обновления-документации-обновление-не-требуется" tabindex="-1">Обновления документации (обновление не требуется) <a class="header-anchor" href="#обновления-документации-обновление-не-требуется" aria-label="Permalink to &quot;Обновления документации (обновление не требуется)&quot;">​</a></h3><ul><li>Обновления документации не влияют на функциональность, можно просмотреть README вручную</li></ul><hr><h2 id="известные-проблемы" tabindex="-1">Известные проблемы <a class="header-anchor" href="#известные-проблемы" aria-label="Permalink to &quot;Известные проблемы&quot;">​</a></h2><h3 id="текущая-версия-2026-01-24" tabindex="-1">Текущая версия (2026-01-24) <a class="header-anchor" href="#текущая-версия-2026-01-24" aria-label="Permalink to &quot;Текущая версия (2026-01-24)&quot;">​</a></h3><ul><li>Критических проблем не обнаружено</li></ul><h3 id="предыдущие-версии" tabindex="-1">Предыдущие версии <a class="header-anchor" href="#предыдущие-версии" aria-label="Permalink to &quot;Предыдущие версии&quot;">​</a></h3><ul><li>До 2026-01-22: Загрузка хуков требовала ручной настройки (исправлено в 2026-01-22)</li><li>До 2026-01-20: Не поддерживалась Windows (исправлено в 2026-01-22)</li></ul><hr><h2 id="участие-и-обратная-связь" tabindex="-1">Участие и обратная связь <a class="header-anchor" href="#участие-и-обратная-связь" aria-label="Permalink to &quot;Участие и обратная связь&quot;">​</a></h2><h3 id="сообщение-о-проблемах" tabindex="-1">Сообщение о проблемах <a class="header-anchor" href="#сообщение-о-проблемах" aria-label="Permalink to &quot;Сообщение о проблемах&quot;">​</a></h3><p>Если вы обнаружили баг или у вас есть предложение:</p><ol><li>Поищите похожую проблему в <a href="https://github.com/affaan-m/everything-claude-code/issues" target="_blank" rel="noreferrer">GitHub Issues</a></li><li>Если не нашли — создайте новый Issue, указав: <ul><li>Информацию о версии</li><li>Операционную систему</li><li>Шаги воспроизведения</li><li>Ожидаемое поведение vs фактическое поведение</li></ul></li></ol><h3 id="отправка-pr" tabindex="-1">Отправка PR <a class="header-anchor" href="#отправка-pr" aria-label="Permalink to &quot;Отправка PR&quot;">​</a></h3><p>Мы рады вкладу! Ознакомьтесь с <a href="https://github.com/affaan-m/everything-claude-code/blob/main/CONTRIBUTING.md" target="_blank" rel="noreferrer">CONTRIBUTING.md</a> для подробностей.</p><hr><h2 id="итоги-урока" tabindex="-1">Итоги урока <a class="header-anchor" href="#итоги-урока" aria-label="Permalink to &quot;Итоги урока&quot;">​</a></h2><ul><li>Everything Claude Code использует версионирование по дате (<code>YYYY-MM-DD</code>)</li><li>Исправления безопасности (например, 2026-01-24) требуют обязательного обновления</li><li>Улучшения функциональности — обновляйтесь по необходимости</li><li>Пользователи маркетплейса обновляются через <code>/plugin update</code></li><li>При ручной установке используйте <code>git pull</code></li><li>При сообщении о проблемах и отправке PR следуйте руководству проекта</li></ul><h2 id="анонс-следующего-урока" tabindex="-1">Анонс следующего урока <a class="header-anchor" href="#анонс-следующего-урока" aria-label="Permalink to &quot;Анонс следующего урока&quot;">​</a></h2><blockquote><p>В следующем уроке мы изучим <strong><a href="./../../appendix/config-reference/">Справочник по конфигурации</a></strong>.</p><p>Вы узнаете:</p><ul><li>Полное описание полей <code>settings.json</code></li><li>Расширенные параметры конфигурации хуков</li><li>Подробности настройки MCP-серверов</li><li>Лучшие практики пользовательской конфигурации</li></ul></blockquote>',64)])])}const p=a(o,[["render",r]]);export{g as __pageData,p as default};
